// 1) Entradas del webhook
const ycbmUrl = $input.first().json.body.ycbmUrl
// 2) Separamos host y query
const [beforeQuery, afterQuery = ''] = ycbmUrl.split('?');
const host = beforeQuery.split('//')[1].split('/')[0];     // "santifer-citav2-componentes.youcanbook.me"
const subdomain = host.split('.')[0];                      // "santifer-citav2-componentes"

// 3) Parseamos la query string (clave=valor&...)
const queryVars = {};
if (afterQuery) {
  afterQuery.split('&').forEach(pair => {
    const [rawKey, rawVal = ''] = pair.split('=');
    const key   = rawKey.toUpperCase();
    const val   = decodeURIComponent(rawVal.replace(/\+/g, ' '));
    queryVars[key] = val;
  });
}

// … tu lógica de parsing …

const result = {
  subdomain,
  queryVars
};

// Devuelve un único string (JSON), no un objeto
return result;

// 1) Ranges que devolvió tu Agente IA
const ranges = Array.isArray($('AnalizarDisponibilidad').first().json.output)
  ? $('AnalizarDisponibilidad').first().json.output
  : [];

// 2) Disponibilidades (cada item con freeUnits y startsAt)
const availItems = $input.first().json.slots

// 3) Formatters para fecha y hora en Europe/Madrid
const fmtDate = new Intl.DateTimeFormat('sv', {
  timeZone: 'Europe/Madrid',
  year:     'numeric',
  month:    '2-digit',
  day:      '2-digit',
});  
const fmtTime = new Intl.DateTimeFormat('en-GB', {
  timeZone:  'Europe/Madrid',
  hour12:    false,
  hour:      '2-digit',
  minute:    '2-digit',
});

const slots = [];

// 4) Por cada rango, filtramos
for (const r of ranges) {
  for (const o of availItems) {
    const ts = Number(o.startsAt);
    const d  = new Date(ts);

    // 4.1 Obtener fecha local en España: "YYYY-MM-DD"
    const localDate = fmtDate.format(d);  

    if (localDate !== r.date) continue;

    // 4.2 Obtener hora local en España: ["HH","mm"]
    const [hour, minute] = fmtTime.format(d).split(':');
    const localTime = `${hour}:${minute}`;

    // 4.3 Comparar con r.start y r.end (ambos "HH:mm")
    if (localTime >= r.start && localTime < r.end) {
      slots.push({
        date:      r.date,
        timestamp: ts,
        start:     localTime,
      });
    }
  }
}

// 5) Emitir resultado
// Devuelve SIEMPRE un array de items:
//  - si slots.length===0 → [], 
//  - si slots.length===1 → [el único slot], 
//  - si slots.length>1 → [todos los slots]
return [
  {
    json: {
      slots                     // el array completo, aunque sea []
    }
  }
];

// 1) Datos de entrada
const queryVars =  $('ParseURL').first().json.queryVars || {};
const subdomain =  $('ParseURL').first().json.subdomain || {};
const timestamp = $('FilterSlots').first().json.slots[0].timestamp
const email     = $('Webhook').first().json.body.email;
const telefono  = $('Webhook').first().json.body.telefono;
const comentarios  = $('Webhook').first().json.body.comentarios;
const textDiag= 'Diagnóstico';

// 2) Creamos el body plano
// … tu lógica para timestamp, queryVars, email y telefono …
const body = {
  startsAt:     timestamp,
  form: [
    { id: "EMAIL", value: email },
    { id: "Q2",    value: telefono },
    { id: "Q5",    value: true },
    // y ahora los campos de queryVars dinámicos:
    ...Object.entries(queryVars).map(([k,v]) => ({ id: k, value: v })),
  ]
};

if (subdomain.includes('diagnostico')) {
  const comentarios2 = 'Cita de diagnóstico tomada por Jacobo: ' + comentarios
  body.form.push({ id: 'Q6', value: comentarios2 ?? '' });
  body.form.push({ id: 'REP', value: textDiag ?? '' });
}

return [{ json: body }];


// si mañana tienes OTRACOSA en queryVars, añade otro if...

// 4) Devolvemos un único item con el body listo para el HTTP Request
return [
  { json: body }
];

// Function node: pide al cliente su email para confirmar la cita
return [
  {
    json: {
      message: "INSTRUCCIONES AL AGENTE: Solicita el email al usuario para poder confirmar la cita."
    }
  }
];

// Function node: pide al cliente su email para confirmar la cita
return [
  {
    json: {
      message: "INSTRUCCIONES AL AGENTE: La cita está confirmada y le llegará un whatsapp y correo con la confirmación, informa al usuario"
    }
  }
];

// 0) Capturar la petición original (ajusta el nombre del nodo y campo si fuese necesario)
const peticionInicial = $('Webhook').first().json.body.preferencia || "";

// 1) Aplanar todos los slots entrantes en un solo array
let flatSlots = [];
$input.all().forEach(item => {
  const j = item.json;
  if (Array.isArray(j.slots)) {
    flatSlots = flatSlots.concat(j.slots);
  } else if (j.date && j.start) {
    flatSlots.push({ date: j.date, start: j.start });
  }
});

// 2) Agrupar los slots por fecha
const agrupadoPorFecha = flatSlots.reduce((acum, { date, start }) => {
  if (!acum[date]) acum[date] = [];
  acum[date].push(start);
  return acum;
}, {});

// 3) Construir el array de disponibilidad con nombres de campo en español
const disponibilidad = Object.entries(agrupadoPorFecha).map(([fecha, horas]) => ({
  fecha,
  horas
}));

// 4) Generar el mensaje con instrucciones para el agente IA
let mensaje = "";
if (peticionInicial && disponibilidad.length > 0) {
  mensaje = 
    "INSTRUCCIONES AL AGENTE:\n" +
    "– Existe una petición inicial (“peticionInicial” no está vacía) y hay disponibilidad.\n" +
    "– Debes solicitar al usuario que elija entre las franjas disponibles listadas en “disponibilidad”.";
} else if (peticionInicial && disponibilidad.length === 0) {
  mensaje = 
    "INSTRUCCIONES AL AGENTE:\n" +
    "– Existe una petición inicial pero no hay disponibilidad en esa fecha.\n" +
    "– Debes informar al usuario que no falta disponibilidad en la fecha solicitada y ofrecerle otras fechas distintas que aparecen en “disponibilidad” (que estará vacío).";
} else if (!peticionInicial && disponibilidad.length > 0) {
  mensaje = 
    "INSTRUCCIONES AL AGENTE:\n" +
    "– El usuario no indicó preferencia horaria.\n" +
    "– Debes mostrar las próximas franjas disponibles que se encuentran en " + disponibilidad + ".\n" +
    "– Pregunta amablemente al usuario qué día y hora le viene mejor de las opciones disponibles.";
} else { // !peticionInicial && disponibilidad.length === 0
  mensaje = 
    "INSTRUCCIONES AL AGENTE:\n" +
    "– No hay petición inicial y tampoco hay disponibilidad.\n" +
    "– Debes informar al usuario de que no hay huecos libres en este momento y sugerirle que intente más adelante.";
}

// 5) Devolver un único objeto JSON con claves descriptivas
return [{
  json: {
    peticionInicial,
    disponibilidad,
    mensaje
  }
}];
